define i64 @test30(i32 %A, i32 %B) {
  %C = zext i32 %A to i64
  %D = zext i32 %B to i64
  %E = mul i64 %C, %D
  ret i64 %E
}

@PR22087 = external global i32

define i32 @test31(i32 %V) {
  %cmp = icmp ne ptr inttoptr (i64 4 to ptr), @PR22087
  %ext = zext i1 %cmp to i32
  %shl = shl i32 1, %ext
  %mul = mul i32 %V, %shl
  ret i32 %mul
}

define i64 @test30(i32 %A, i32 %B) {
  %C = zext i32 %A to i64
  %D = zext i32 %B to i64
  %E = mul i64 %C, %D
  ret i64 %E
}

